import React, { useEffect } from 'react'
import Layout from '../components/Layout'
import { Helmet } from 'react-helmet'
import { Bell, Globe, HelpCircle, UserCircle, UserCircle2 } from 'lucide-react'
import ProfileSection from '../components/ProfilePageComponents/profile-section'
import useAuth from '../components/useAuth'
import { navigate } from "gatsby"
import { Auth } from 'aws-amplify';

const Profile = (props) => {

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const user = await Auth.currentAuthenticatedUser();
        if(!user || !(user?.attributes?.email_verified)) navigate("/");
      } catch (error) {
        console.log(error);
        navigate("/");
      }
    };
    fetchUser();
  }, []);
  

  return (
    <Layout includePreFooter>
    <Helmet>
      <title>Profile</title>
      <meta name='description' content={"asdfasdfa"} />
    </Helmet>

    {/* ----- Meat of the code  ------  */}
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-64 bg-white p-6 shadow-md">
        <h1 className="text-2xl font-bold mb-8"></h1>

        <nav className="space-y-6">
          <div className="flex items-center space-x-4 text-gray-700 cursor-pointer hover:text-gray-900">
            <UserCircle2 className="text-2xl" />
            <span className="text-lg font-medium">Profile</span>
          </div>
          <div className="flex items-center space-x-4 text-gray-700 cursor-pointer hover:text-gray-900">
            <Bell className="text-2xl" />
            <span className="text-lg font-medium">Notifications</span>
          </div>
          <div className="flex items-center space-x-4 text-gray-700 cursor-pointer hover:text-gray-900">
            <HelpCircle className="text-2xl" />
            <span className="text-lg font-medium">Support</span>
          </div>
        </nav>
      </aside>

      {/* Profile Section */}
      <ProfileSection />

      {/* Top Right Icons */}
      {/* <div className="absolute top-6 right-8 flex space-x-6 text-gray-700">
        <UserCircle className="text-2xl cursor-pointer" />
        <div className="w-8 h-8 border rounded-md flex items-center justify-center cursor-pointer">
          🏦
        </div>
      </div> */}
    </div>
    
  </Layout>
)
  
}

export default Profile