import { Globe } from 'lucide-react';
import React, { useEffect, useMemo, useRef, useState } from 'react';
import useAuth from '../useAuth';
import ReactAvatar from 'react-avatar';
import { API, Storage } from 'aws-amplify';
import { getFromBucket, getProfileByAuthId, storeOnBucket, updateProfileForUser, websiteApi } from '../../service/Profile.service'

import { updateProfile } from '../../graphql/mutations';

const ProfileSection = () => {
  const { currentUser } = useAuth();
  const inputRef = useRef({});
  const idCardRef = useRef();
  const [pic, setPic] = useState(null);
  const [picRender, setPicRender] = useState(null);
  useEffect(()=>{
    
  },[])
  // const imageRef = useRef(null);
  const [profileLoaded, setProfileLoaded] = useState(false);

  function handleChange(e) {
    if (e.target.files && e.target.files[0]) {
      idCardRef.current = e.target.files[0];
    }
    const { name, value } = e.target;
    inputRef.current[name] = value;
  }
  let valueByAuth = null;

  async function handleSave() {
    try {
      const { __typename, createdAt,updatedAt , ...otherInput} = inputRef.current;
      let picture_url = null, card_url = null;
      if(pic){
       picture_url =  await storeOnBucket({ file: pic, type: "profile", currentUser})
      }
      if(idCardRef.current){
        card_url = await storeOnBucket({file: idCardRef.current, type:"id_card", currentUser})
      }
      // console.log({ picture_url, card_url})
      const profile = await updateProfileForUser({
        input: {
          ...otherInput,
          profile_picture: picture_url?.key ?? null, 
          id_card: card_url?.key ?? null,
        },
        condition:{ 
          auth_id: { eq: currentUser?.attributes?.sub },
        }
      });

      
      alert('Profile saved successfully!');
    } catch (error) {
      console.error('Error saving profile:', error);
    }
  }

  function handleFileChange(e){
    setPic(e.target.files[0]);
    const reader = new FileReader();
    reader.onloadend = () => {
      setPicRender(reader.result);
    };
    reader.readAsDataURL(e.target.files[0]);
  }


  useEffect(() => {
    async function fetchProfile() {
      try {
       

        // TODO: This function is on build 

        // valueByAuth = await API.graphql({
        //   query: getProfileByAuthId,
        //   variables: {
        //     authId: currentUser?.attributes?.sub,
        //   },
        // })
        const profileData = await getProfileByAuthId(currentUser?.attributes?.sub);

        const profile = profileData?.data?.listProfiles?.items[0] || {};
        inputRef.current = profile;
        // Get picture here: 
        if(inputRef?.current?.profile_picture){
          const key = await getFromBucket(inputRef?.current?.profile_picture);
          setPicRender(key);       
        }
        setProfileLoaded(true);
      } catch (error) {
        console.error('Error fetching profile:', error);
      }
    }

    if (currentUser?.attributes?.sub) {
      fetchProfile();
    }
  }, [currentUser]);

  return (
    <>
      {/* Profile Section */}
      <main className="flex-1 p-10">
        <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-lg">
          <h2 className="text-3xl font-bold mb-6">Profile</h2>

          {/* Profile Picture */}
          <div className="flex items-center space-x-6 mb-6">
            <div className="relative">
              <div className="w-24 h-24 rounded-full bg-gray-300 flex items-center justify-center text-lg shadow-md overflow-hidden">
                <ReactAvatar
                  size="96"
                  round
                  // src='https://images.unsplash.com/photo-1736687107097-0022360964fb?q=80&w=1915&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'
                  src={picRender}
                  name={currentUser?.username || "Noobie Learner"}
                  className="cursor-pointer"
                />
              </div>
              <label
                htmlFor="profile-pic"
                className="absolute bottom-0 right-0 bg-blue-600 text-white text-xs font-medium py-1 px-3 rounded-full cursor-pointer hover:bg-blue-700 transition-all"
              >
                Change
              </label>
              <input
                id="profile-pic"
                type="file"
                className="hidden"
                onChange={handleFileChange}
                accept="image/*"
              />
            </div>
            <div>
              <p className="text-gray-700 font-medium">Profile Picture</p>
              <p className="text-sm text-gray-500">
                Upload a new image (JPG, PNG, GIF)
              </p>
            </div>
          </div>

          {/* Form Fields */}
          <div className="space-y-4">
            <div>
              <label className="block font-medium text-gray-700">
                Username
              </label>
              <input
                type="text"
                className="w-full border border-gray-300 rounded-md p-2 mt-1"
                defaultValue={inputRef.current.username || ""}
                name="username"
                onChange={handleChange}
              />
            </div>

            <div>
              <label className="block font-medium text-gray-700">Bio</label>
              <textarea
                className="w-full border border-gray-300 rounded-md p-2 mt-1"
                rows="3"
                defaultValue={inputRef.current.bio || ""}
                name="bio"
                onChange={handleChange}
              ></textarea>
            </div>

            <div>
              <label className="block font-medium text-gray-700">
                Email Address
              </label>
              <input
                type="email"
                className="w-full border border-gray-300 rounded-md p-2 mt-1"
                defaultValue={inputRef.current.email || ""}
                name="email"
                onChange={handleChange}
              />
            </div>

            {/* Social Connections */}
            {/* <div className="flex items-center justify-between border border-gray-300 rounded-md p-2">
              <div className="flex items-center space-x-2">
                <span className="text-gray-700">Instagram</span>
              </div>
              <button className="bg-blue-500 text-white px-4 py-1 rounded-md">
                Connect
              </button>
            </div> */}

            <div className="flex items-center border border-gray-300 rounded-md p-2">
              <label
                htmlFor="id_card"
                className="block text-sm font-semibold text-teal-200 text-left"
              >
                Upload ID Card:
              </label>
              <input
                type="file"
                id="id_card"
                className="w-full border-none focus:ring-0"
                accept=".pdf, image/*"
                placeholder="Enter your official ID"
                defaultValue={inputRef.current.website || ""}
                name="id_card"
                onChange={handleChange}
              />
            </div>

            {/* Links */}
            {/* <div className="flex items-center border border-gray-300 rounded-md p-2">
              <Globe className="text-gray-600 mr-2" />
              <input
                type="text"
                className="w-full border-none focus:ring-0"
                placeholder="Enter your IG profile link"
                defaultValue={inputRef.current.website || ""}
                name="website"
                onChange={handleChange}
              />
            </div> */}

            <div>
              <label className="block font-medium text-gray-700">
                Wallet Address
              </label>
              <input
                type="text"
                className="w-full border border-gray-300 rounded-md p-2 mt-1"
                name="wallet_address"
                defaultValue={inputRef.current.wallet_address || ""}
                placeholder="Your wallet address"
                onChange={handleChange}
              />
            </div>

            {/* Save Button */}
            <button
              onClick={handleSave}
              className="w-full bg-blue-500 text-white p-3 rounded-md font-medium"
              disabled={!profileLoaded}
            >
              Save
            </button>
          </div>
        </div>
      </main>
    </>
  );
};

export default ProfileSection;
